// ============================================================
// EVALUADOR DE PREDICCIONES vs RESULTADOS REALES
// Salida: 5 booleanos por modelo + 1 booleano de fecha + números acertados
// ============================================================

// ── 1. CONFIGURACIÓN DE ENTRADA ──────────────────────────────
const realesRaw = $('Setear DatosLG').all().map(i => i.json);
const prediccionesRaw = $('Tabla Lotto Activo').all().map(i => i.json);
const MODELOS = ['Gemma 31B', 'Gemma 26B', 'Mistral', 'Llama 3.3 70B', 'GPT'];

// ── 2. NORMALIZAR HORA ───────────────────────────────────────
function normalizarHora(horaStr) {
  if (!horaStr) return null;
  let h = horaStr.trim().toUpperCase().replace(/\s/g, '');
  h = h.replace(':00', '');
  if (h.match(/^\d[AP]M$/)) h = '0' + h;
  return h;
}

// ── 3. MAPA DE RESULTADOS REALES ─────────────────────────────
const realMap = {};
realesRaw.forEach(r => {
  if (!r.fecha || !r.hora || r.numero === undefined) return;
  const fecha = r.fecha;
  const hora = normalizarHora(r.hora);
  if (!realMap[fecha]) realMap[fecha] = {};
  realMap[fecha][hora] = String(r.numero);
});

// ── 4. OBTENER PREDICCIÓN MÁS RECIENTE ───────────────────────
function parseFechaPrediccion(fechaStr) {
  if (!fechaStr) return null;
  const match = fechaStr.match(/(\w+)\s+(\d+)(?:st|nd|rd|th)?\s+(\d{4})/);
  if (!match) return null;
  const meses = {
    January:'01', February:'02', March:'03', April:'04', May:'05', June:'06',
    July:'07', August:'08', September:'09', October:'10', November:'11', December:'12'
  };
  const mes = meses[match[1]];
  if (!mes) return null;
  const dia = match[2].padStart(2, '0');
  const año = match[3];
  return `${año}-${mes}-${dia}`;
}

let latestPred = null;
let latestDate = null;
for (const p of prediccionesRaw) {
  const fecha = parseFechaPrediccion(p['Fecha Prediccion']);
  if (fecha && (!latestDate || fecha > latestDate)) {
    latestDate = fecha;
    latestPred = p;
  }
}

// ── 5. PARSEAR SECUENCIAS (con soporte para ausencia de predicciones) ──
function parseSequence(val) {
  if (!val) return null;
  try {
    const obj = typeof val === 'string' ? JSON.parse(val) : val;
    const res = {};
    for (const [h, n] of Object.entries(obj)) {
      res[h] = String(n);
    }
    return res;
  } catch {
    return null;
  }
}

// Inicializar estructuras por si no hay predicciones
let prediccionesPorModelo = {};
let hayPredicciones = false;
let fechaPrediccion = null;

if (latestPred) {
  hayPredicciones = true;
  fechaPrediccion = latestDate;
  for (const modelo of MODELOS) {
    prediccionesPorModelo[modelo] = parseSequence(latestPred[modelo]);
  }
} else {
  // Sin predicciones: asignamos null a todos los modelos
  for (const modelo of MODELOS) {
    prediccionesPorModelo[modelo] = null;
  }
}

// ── 6. EVALUAR ACIERTOS Y GUARDAR NÚMEROS ACERTADOS ──────────
const realesDeEsaFecha = (fechaPrediccion && realMap[fechaPrediccion]) ? realMap[fechaPrediccion] : {};
const aciertos = {};
const numerosPredichos = {};
const aciertosNumeros = {};

for (const modelo of MODELOS) {
  const seq = prediccionesPorModelo[modelo];
  if (!seq) {
    aciertos[modelo] = 0;
    numerosPredichos[modelo] = [];
    aciertosNumeros[modelo] = [];
    continue;
  }
  let hits = 0;
  const nums = [];
  const aciertosNums = [];
  for (const [hora, numPred] of Object.entries(seq)) {
    nums.push(numPred);
    if (realesDeEsaFecha[hora] === numPred) {
      hits++;
      aciertosNums.push({ hora, numero: numPred });
    }
  }
  aciertos[modelo] = hits;
  numerosPredichos[modelo] = nums;
  aciertosNumeros[modelo] = aciertosNums;
}

// ── 7. VARIABLES DE DECISIÓN ─────────────────────────────────
const acerto_gemma31b = aciertos['Gemma 31B'] > 0;
const acerto_gemma26b = aciertos['Gemma 26B'] > 0;
const acerto_mistral   = aciertos['Mistral'] > 0;
const acerto_llama     = aciertos['Llama 3.3 70B'] > 0;
const acerto_gpt       = aciertos['GPT'] > 0;

// Comparar fecha de predicción con fecha actual (si hay fecha)
const hoy = new Date().toISOString().slice(0,10);
const fecha_coincide_hoy = (fechaPrediccion === hoy);

// ── 8. SALIDA FINAL (siempre completa) ───────────────────────
return [{
  json: {
    // Bandera que indica si se encontraron predicciones
    hay_predicciones: hayPredicciones,

    // 5 booleanos por modelo (si no hay predicciones, todos false)
    acerto_gemma31b,
    acerto_gemma26b,
    acerto_mistral,
    acerto_llama,
    acerto_gpt,

    // Booleano de fecha (false si no hay predicciones)
    fecha_coincide_hoy,

    // Números que acertó cada modelo (vacíos si no hay predicciones)
    aciertos_numeros_por_modelo: aciertosNumeros,

    // Información extra
    fecha_prediccion: fechaPrediccion || null,
    aciertos_por_modelo: aciertos,
    numeros_por_modelo: numerosPredichos,
    total_predicciones: hayPredicciones ? 12 : 0,
    total_aciertos: hayPredicciones ? Object.values(aciertos).reduce((s, v) => s + v, 0) : 0
  }
}];
